  // Helper function to get timeline events based on MRN or page type
  // Add your timeline data constants here, then map them below
  function getTimelineEventsForMrn(mrn, pageType) {
    // Map MRNs to their specific timeline event arrays
    // You can add new MRNs and their corresponding event arrays here
    
    const timelineDataMap = {
      // Map specific MRNs to their timeline data
      '25GBBVWP03XACE8AR0': CANCELLED_TIMELINE_EVENTS,
      '25GBCLNTWCC1FN7AR0': MANUAL_RELEASE_TIMELINE_EVENTS,
      // Handle legacy variants with 'O' instead of '0'
      '25GBBVWP03XACE8ARO': CANCELLED_TIMELINE_EVENTS,
      '25GBCLNTWCC1FN7ARO': MANUAL_RELEASE_TIMELINE_EVENTS,
    };
    
    // First check for MRN-specific mapping
    if (timelineDataMap[mrn]) {
      return timelineDataMap[mrn];
    }
    
    // Then check for page-type-specific mapping
    if (timelineDataMap[pageType]) {
      return timelineDataMap[pageType];
    }
    
    // Default to sample events
    return SAMPLE_TIMELINE_EVENTS;
  }

  // GET: Consignment timeline page
  router.get('/mvp/v5/timeline/consignment-timeline', (req, res) => {
    const mrn = req.query.mrn || '25GBC64QCLFMUHPAR2';
    const eventType = req.query.eventType || req.session.data?.eventType || 'all';
    // Always show newest to oldest (descending order)
    const sortBy = req.query.sortBy || req.session.data?.sortBy || 'descending';

    // Process timeline events using helper function
    const filteredEvents = processTimelineEvents(eventType, sortBy);

    res.render('mvp/v5/timeline/consignment-timeline', {
      mrn,
      timelineEvents: filteredEvents,
      data: {
        eventType,
        sortBy
      }
    });
  });

  // POST: Handle filter changes
  router.post('/mvp/v5/timeline/consignment-timeline', (req, res) => {
    const eventType = req.body.eventType || 'all';
    const sortBy = req.body.sortBy || 'descending';
    const mrn = req.body.mrn || req.query.mrn || '25GBCLNTWCC1FN7AR0';

    req.session.data = req.session.data || {};
    req.session.data.eventType = eventType;
    req.session.data.sortBy = sortBy;

    res.redirect(`/mvp/v5/timeline/consignment-timeline?mrn=${encodeURIComponent(mrn)}&eventType=${eventType}&sortBy=${sortBy}`);
  });

  // Helper function to process timeline events (used by both routes)
  function processTimelineEvents(eventType, sortBy, eventsArray = null) {
    // Use provided events array or default to SAMPLE_TIMELINE_EVENTS
    const sourceEvents = eventsArray || SAMPLE_TIMELINE_EVENTS;
    
    // Filter events by type
    let filteredEvents = sourceEvents;
    if (eventType !== 'all') {
      filteredEvents = sourceEvents.filter(event => {
        if (eventType === 'finalisation') return event.title === 'Finalisation';
        if (eventType === 'clearance-decision') return event.title === 'Clearance decision';
        if (eventType === 'clearance-request') return event.title === 'Clearance request';
        if (eventType === 'ched' || eventType === 'ipaffs-pre-notification') return event.title.startsWith('CHED');
        return true;
      });
    }

    // Format dates and sort events by created time
    filteredEvents = filteredEvents.map(event => ({
      ...event,
      createdFormatted: formatDateForDisplay(event.created)
    }));

    // Always sort by created time (descending = newest first, ascending = oldest first)
    // Secondary sort by title to ensure consistent ordering when timestamps are identical
    filteredEvents.sort((a, b) => {
      const dateA = new Date(a.created).getTime();
      const dateB = new Date(b.created).getTime();
      
      // Primary sort by date
      if (dateA !== dateB) {
        return sortBy === 'ascending' ? dateA - dateB : dateB - dateA;
      }
      
      // Secondary sort by title for events with identical timestamps
      return a.title.localeCompare(b.title);
    });

    return filteredEvents;
  }

